insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'In a code, each letter is shifted 1 places forward. How is TRAIN coded?', 'एक code में हर letter 1 places आगे shift होता है। TRAIN को कैसे code करेंगे?', 'Move every letter of TRAIN forward by 1: TRAIN becomes USBJO. Therefore, answer = USBJO.', 'Letter-shift coding uses alphabet positions. Apply the same displacement to each character and wrap after Z if needed. Final answer is USBJO.', 'TRAIN के हर letter को 1 आगे करें: TRAIN का code USBJO होगा। अतः answer = USBJO।', 'Letter-shift coding में alphabet positions use होते हैं। हर character पर same displacement लगाएँ। Final answer USBJO है।', 'EASY', array['coding-decoding','letter-shift']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'USBJO', 'USBJO', true, null, null);
