insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'NIART', 'NIART', false, 'Reversed the word but did not apply the letter shift.', 'Word reverse किया पर letter shift apply नहीं किया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'OJBSU', 'OJBSU', false, 'Applied the shift but also reversed the result, which the rule never says.', 'Shift apply करके result reverse भी कर दिया, जबकि rule में reverse नहीं है।');
